const data = $input.all()[0].json.data;

// Initialize totals
let totalSpend = 0;
let totalPaidViews = 0;
let totalPaidLikes = 0;
let totalPaidShares = 0;
let totalPaidFollowers = 0;

// Loop through each day
data.forEach(day => {
  const spend = parseFloat(day.spend || 0);
  totalSpend += spend;

  // Find actions
  const actions = day.actions || [];

  // Get counts for specific action_types
  const videoViews = actions.find(a => a.action_type === "video_view")?.value || 0;
  const postReactions = actions.find(a => a.action_type === "post_reaction")?.value || 0;
  const postEngagement = actions.find(a => a.action_type === "post_engagement")?.value || 0;
  const pageEngagement = actions.find(a => a.action_type === "page_engagement")?.value || 0;

  // Aggregate totals
  totalPaidViews += Number(videoViews);
  totalPaidLikes += Number(postReactions);
  totalPaidShares += Number(postEngagement) - Number(postReactions);
  totalPaidFollowers += Number(pageEngagement);
});

// Calculate cost metrics safely (avoid division by 0)
const cpv = totalPaidViews ? totalSpend / totalPaidViews : 0;
const cpl = totalPaidLikes ? totalSpend / totalPaidLikes : 0;
const cps = totalPaidShares ? totalSpend / totalPaidShares : 0;
const cpf = totalPaidFollowers ? totalSpend / totalPaidFollowers : 0;

// Return result as a single JSON with numbers
return [
  {
    json: {
      FBPaid_totalSpend: Number(totalSpend.toFixed(2)),
      FBPaid_totalViews: totalPaidViews,
      FBPaid_totalLikes: totalPaidLikes,
